import { createClient } from '@supabase/supabase-js';
import * as fs from 'fs';
import * as path from 'path';

const supabaseUrl = process.env.NEXT_PUBLIC_SUPABASE_URL || 'https://yxhzkbzmnvhesdefwgjc.supabase.co';
const supabaseKey = process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY;

if (!supabaseKey) {
  console.error('Missing NEXT_PUBLIC_SUPABASE_ANON_KEY');
  process.exit(1);
}

const supabase = createClient(supabaseUrl, supabaseKey);

const users = [
  { email: 'admin@curimana.gob.pe', password: 'password', role: 'admin' },
  { email: 'cajero@curimana.gob.pe', password: 'password', role: 'cashier' },
  { email: 'lector@curimana.gob.pe', password: 'password', role: 'meter_reader' }
];

async function main() {
  for (const user of users) {
    const { data, error } = await supabase.auth.signUp({
      email: user.email,
      password: user.password,
      options: {
        data: {
          full_name: `Test ${user.role}`
        }
      }
    });

    if (error) {
      console.log(`Failed to create ${user.email}:`, error.message);
    } else {
      console.log(`Created ${user.email}`);
    }
  }
}

main();

import { describe, it, expect, vi } from 'vitest'
import { CustomerService } from '@/services/customer-service'
import { CustomerRepository } from '@/repositories/customer-repository'

vi.mock('@/repositories/customer-repository')

describe('Customer Management Integration Flow', () => {
  const service = new CustomerService()
  const proto = CustomerRepository.prototype

  it('debería registrar un cliente con número de suministro generado automáticamente', async () => {
    const mockSupplyNumber = '202604001'
    const customerData = {
      full_name: 'Juan Perez',
      address: 'Calle Falsa 123',
      sector: 'Sector 1',
      tariff_id: 'tariff-uuid',
      connection_type: 'monofásico' as const,
      document_number: '12345678',
      phone: '987654321',
      is_active: true
    }

    vi.spyOn(proto, 'generateSupplyNumber').mockResolvedValue(mockSupplyNumber)
    vi.spyOn(proto, 'create').mockImplementation(async (data: any) => ({
      id: 'new-uuid',
      created_at: new Date().toISOString(),
      updated_at: new Date().toISOString(),
      current_debt: 0,
      ...data
    }))

    const result = await service.registerCustomer(customerData)

    expect(proto.generateSupplyNumber).toHaveBeenCalled()
    expect(proto.create).toHaveBeenCalledWith({
      ...customerData,
      supply_number: mockSupplyNumber
    })
    expect(result.supply_number).toBe(mockSupplyNumber)
    expect(result.full_name).toBe('Juan Perez')
  })

  it('debería encontrar un cliente por su número de suministro', async () => {
    const mockCustomer = {
      id: 'uuid-123',
      full_name: 'Maria Garcia',
      supply_number: '202604999',
      current_debt: 0
    }

    vi.spyOn(proto, 'searchCustomers').mockResolvedValue([mockCustomer] as any)

    const results = await service.searchCustomers('202604999')

    expect(proto.searchCustomers).toHaveBeenCalledWith('202604999')
    expect(results).toHaveLength(1)
    expect(results[0].supply_number).toBe('202604999')
  })
})

import { describe, it, expect, vi, beforeEach } from 'vitest'
import { AuditService } from '@/services/audit-service'
import { AuditRepository } from '@/repositories/audit-repository'

vi.mock('@/repositories/audit-repository')

describe('AuditService', () => {
  const service = new AuditService()

  beforeEach(() => {
    vi.restoreAllMocks()
  })

  describe('log', () => {
    it('debería registrar un log con ip_address por defecto', async () => {
      vi.spyOn(AuditRepository.prototype, 'create').mockResolvedValue({ id: 'a1' } as any)

      await service.log({
        table_name: 'receipts',
        record_id: 'r1',
        action: 'UPDATE',
        old_data: { status: 'pending' },
        new_data: { status: 'cancelled' },
        user_id: 'user1'
      })

      expect(AuditRepository.prototype.create).toHaveBeenCalledWith(
        expect.objectContaining({
          table_name: 'receipts',
          record_id: 'r1',
          action: 'UPDATE',
          ip_address: '0.0.0.0'
        })
      )
    })

  it('debería lanzar error si el repositorio falla', async () => {
    vi.spyOn(AuditRepository.prototype, 'create').mockRejectedValue(new Error('DB error'))

    await expect(service.log({
      table_name: 'test',
      record_id: '1',
      action: 'INSERT'
    })).rejects.toThrow('DB error')
  })
  })

  describe('getAuditLogs', () => {
    it('debería delegar al repositorio', async () => {
      const mockLogs = [{ id: 'a1', action: 'INSERT' }]
      vi.spyOn(AuditRepository.prototype, 'getAllLogs').mockResolvedValue(mockLogs as any)

      const result = await service.getAuditLogs()

      expect(AuditRepository.prototype.getAllLogs).toHaveBeenCalled()
      expect(result).toEqual(mockLogs)
    })
  })
})

import { describe, it, expect, vi, beforeEach } from 'vitest'
import { CashClosureService } from '@/services/cash-closure-service'
import { CashClosureRepository } from '@/repositories/cash-closure-repository'
import { PaymentRepository } from '@/repositories/payment-repository'

vi.mock('@/repositories/cash-closure-repository')
vi.mock('@/repositories/payment-repository')

describe('CashClosureService', () => {
  const service = new CashClosureService()

  beforeEach(() => {
    vi.restoreAllMocks()
  })

  describe('openClosure', () => {
    it('debería crear un cierre con estado open y monto inicial', async () => {
      vi.spyOn(CashClosureRepository.prototype, 'create').mockResolvedValue({ id: 'cl1' } as any)

      await service.openClosure('user1', 200)

      expect(CashClosureRepository.prototype.create).toHaveBeenCalledWith(
        expect.objectContaining({
          cashier_id: 'user1',
          opening_amount: 200,
          total_collected: 0,
          total_receipts: 0,
          status: 'open'
        })
      )
    })
  })

  describe('closeClosure', () => {
    it('debería calcular totales y cerrar el cierre', async () => {
      const mockClosure = { id: 'cl1', cashier_id: 'user1' }
      const mockPayments = [
        { amount: 50, receipt_id: 'r1' },
        { amount: 30, receipt_id: 'r2' },
        { amount: 20, receipt_id: 'r1' },
      ]

      vi.spyOn(CashClosureRepository.prototype, 'getById').mockResolvedValue(mockClosure as any)
      vi.spyOn(PaymentRepository.prototype, 'getPaymentsByCashier').mockResolvedValue(mockPayments as any)
      vi.spyOn(CashClosureRepository.prototype, 'close').mockResolvedValue({ id: 'cl1', status: 'closed' } as any)

      await service.closeClosure('cl1')

      expect(PaymentRepository.prototype.getPaymentsByCashier).toHaveBeenCalledWith('user1')
      expect(CashClosureRepository.prototype.close).toHaveBeenCalledWith('cl1', expect.objectContaining({
        total_collected: 100,
        total_receipts: 2
      }))
    })

    it('debería lanzar error si el cierre no existe', async () => {
      vi.spyOn(CashClosureRepository.prototype, 'getById').mockResolvedValue(null as any)

      await expect(service.closeClosure('missing')).rejects.toThrow('No se encontro el cierre de caja')
    })

    it('debería lanzar error si el cierre no tiene cajero', async () => {
      vi.spyOn(CashClosureRepository.prototype, 'getById').mockResolvedValue({ id: 'cl1', cashier_id: null } as any)

      await expect(service.closeClosure('cl1')).rejects.toThrow('El cierre no tiene cajero asociado')
    })
  })
})

import { describe, it, expect, vi, beforeEach } from 'vitest'
import { ConceptService } from '@/services/concept-service'
import { ConceptRepository } from '@/repositories/concept-repository'

vi.mock('@/repositories/concept-repository')

describe('ConceptService', () => {
  const service = new ConceptService()

  beforeEach(() => {
    vi.restoreAllMocks()
  })

  describe('getAllConcepts', () => {
    it('debería delegar al repositorio', async () => {
      const mockConcepts = [{ id: 'c1', name: 'Alumbrado' }]
      vi.spyOn(ConceptRepository.prototype, 'getAll').mockResolvedValue(mockConcepts as any)

      const result = await service.getAllConcepts()

      expect(ConceptRepository.prototype.getAll).toHaveBeenCalled()
      expect(result).toEqual(mockConcepts)
    })
  })

  describe('getActiveConcepts', () => {
    it('debería retornar solo conceptos activos', async () => {
      const mockActive = [{ id: 'c1', is_active: true }]
      vi.spyOn(ConceptRepository.prototype, 'getAllActive').mockResolvedValue(mockActive as any)

      const result = await service.getActiveConcepts()

      expect(ConceptRepository.prototype.getAllActive).toHaveBeenCalled()
      expect(result).toEqual(mockActive)
    })
  })

  describe('createConcept', () => {
    it('debería crear el concepto a través del repositorio', async () => {
      vi.spyOn(ConceptRepository.prototype, 'create').mockResolvedValue({ id: 'c1' } as any)

      await service.createConcept({ code: 'ALUM', name: 'Alumbrado', amount: 4.20, type: 'fixed', is_active: true })

      expect(ConceptRepository.prototype.create).toHaveBeenCalledWith(
        expect.objectContaining({ code: 'ALUM', name: 'Alumbrado' })
      )
    })
  })

  describe('toggleConceptStatus', () => {
    it('debería actualizar is_active en el repositorio', async () => {
      vi.spyOn(ConceptRepository.prototype, 'update').mockResolvedValue({} as any)

      await service.toggleConceptStatus('c1', false)

      expect(ConceptRepository.prototype.update).toHaveBeenCalledWith('c1', { is_active: false })
    })
  })

  describe('deleteConcept', () => {
    it('debería eliminar el concepto a través del repositorio', async () => {
      vi.spyOn(ConceptRepository.prototype, 'delete').mockResolvedValue({} as any)

      await service.deleteConcept('c1')

      expect(ConceptRepository.prototype.delete).toHaveBeenCalledWith('c1')
    })
  })
})

import { describe, it, expect, vi, beforeEach } from 'vitest'
import { CustomerService } from '@/services/customer-service'
import { CustomerRepository } from '@/repositories/customer-repository'

vi.mock('@/repositories/customer-repository')

describe('CustomerService', () => {
  const service = new CustomerService()

  beforeEach(() => {
    vi.restoreAllMocks()
  })

  describe('searchCustomers', () => {
    it('debería delegar la búsqueda al repositorio con trimmed query', async () => {
      const mockResults = [{ id: 'c1', full_name: 'Juan Pérez' }]
      vi.spyOn(CustomerRepository.prototype, 'searchCustomers').mockResolvedValue(mockResults as any)

      const result = await service.searchCustomers('  juan  ')

      expect(CustomerRepository.prototype.searchCustomers).toHaveBeenCalledWith('juan')
      expect(result).toEqual(mockResults)
    })
  })

  describe('registerCustomer', () => {
    it('debería generar supply_number y crear el cliente', async () => {
      vi.spyOn(CustomerRepository.prototype, 'generateSupplyNumber').mockResolvedValue('000000001')
      vi.spyOn(CustomerRepository.prototype, 'create').mockResolvedValue({ id: 'c1', supply_number: '000000001' } as any)

      await service.registerCustomer({
        full_name: 'Juan Pérez',
        document_number: '12345678',
        address: 'Av. Principal 123',
        sector: 'Centro',
        tariff_id: 't1',
        connection_type: 'monofásico',
        is_active: true,
        current_debt: 0,
      })

      expect(CustomerRepository.prototype.generateSupplyNumber).toHaveBeenCalled()
      expect(CustomerRepository.prototype.create).toHaveBeenCalledWith(
        expect.objectContaining({ supply_number: '000000001', full_name: 'Juan Pérez' })
      )
    })
  })

  describe('updateCustomer', () => {
    it('debería delegar la actualización al repositorio', async () => {
      vi.spyOn(CustomerRepository.prototype, 'update').mockResolvedValue({ id: 'c1', is_active: false } as any)

      await service.updateCustomer('c1', { is_active: false } as any)

      expect(CustomerRepository.prototype.update).toHaveBeenCalledWith('c1', { is_active: false })
    })
  })

  describe('getCustomersWithDebt', () => {
    it('debería llamar a getTopDebtors con limite 1000', async () => {
      const mockDebtors = [{ id: 'c1', current_debt: 50 }]
      vi.spyOn(CustomerRepository.prototype, 'getTopDebtors').mockResolvedValue(mockDebtors as any)

      const result = await service.getCustomersWithDebt()

      expect(CustomerRepository.prototype.getTopDebtors).toHaveBeenCalledWith(1000)
      expect(result).toEqual(mockDebtors)
    })
  })
})

import { describe, it, expect, vi, beforeEach } from 'vitest'
import { DashboardService } from '@/services/dashboard-service'

describe('DashboardService - getSummaryKPIs', () => {
  // Mock del cliente de Supabase
  const createMockSupabase = () => ({
    from: vi.fn().mockReturnThis(),
    select: vi.fn().mockReturnThis(),
    gte: vi.fn().mockReturnThis(),
    eq: vi.fn().mockReturnThis(),
    order: vi.fn().mockReturnThis(),
    limit: vi.fn().mockReturnThis(),
    then: vi.fn(),
  })

  it('debería calcular correctamente la recaudación total del mes', async () => {
    const mockSupabase = createMockSupabase()

    // Configurar respuesta para payments
    mockSupabase.gte.mockResolvedValueOnce({ 
      data: [{ amount: 100 }, { amount: 200 }],
      error: null 
    })
    // Configurar respuesta para customers (deuda)
    mockSupabase.eq.mockResolvedValueOnce({ 
      data: [{ current_debt: 50 }, { current_debt: 150 }],
      error: null 
    })
    // Configurar respuesta para count de customers
    mockSupabase.eq.mockResolvedValueOnce({ 
      count: 2,
      data: null,
      error: null 
    })
    // Configurar respuesta para count de receipts
    mockSupabase.eq.mockResolvedValueOnce({ 
      count: 5,
      data: null,
      error: null 
    })

    const service = new DashboardService(mockSupabase as any)
    const kpis = await service.getSummaryKPIs()

    expect(kpis.totalCollected).toBe(300)
  })

  it('debería calcular correctamente la deuda total acumulada', async () => {
    const mockSupabase = createMockSupabase()

    // Configurar respuesta para payments (vacío)
    mockSupabase.gte.mockResolvedValueOnce({ 
      data: [],
      error: null 
    })
    // Configurar respuesta para customers (deuda)
    mockSupabase.eq.mockResolvedValueOnce({ 
      data: [{ current_debt: 50 }, { current_debt: 150 }],
      error: null 
    })
    // Configurar respuesta para count de customers
    mockSupabase.eq.mockResolvedValueOnce({ 
      count: 2,
      data: null,
      error: null 
    })
    // Configurar respuesta para count de receipts
    mockSupabase.eq.mockResolvedValueOnce({ 
      count: 5,
      data: null,
      error: null 
    })

    const service = new DashboardService(mockSupabase as any)
    const kpis = await service.getSummaryKPIs()

    expect(kpis.totalDebt).toBe(200)
  })
})

import { describe, it, expect, vi, beforeEach } from 'vitest'
import { PaymentService } from '@/services/payment-service'
import { ReceiptRepository } from '@/repositories/receipt-repository'
import { CustomerRepository } from '@/repositories/customer-repository'
import { CashClosureRepository } from '@/repositories/cash-closure-repository'
import { PaymentRepository } from '@/repositories/payment-repository'
import { AuditService } from '@/services/audit-service'

vi.mock('@/repositories/receipt-repository')
vi.mock('@/repositories/customer-repository')
vi.mock('@/repositories/payment-repository')
vi.mock('@/repositories/cash-closure-repository')
vi.mock('@/services/audit-service')

describe('PaymentService - processPayment', () => {
  const service = new PaymentService()

  beforeEach(() => {
    vi.restoreAllMocks()
    vi.spyOn(CashClosureRepository.prototype, 'getById').mockResolvedValue({ id: 'cl1', cashier_id: 'user1' } as any)
  })

  it('debería marcar el recibo como PAGADO si el monto cubre el total', async () => {
    const mockReceipt = { id: 'r1', total_amount: 100, paid_amount: 0 }
    const mockCustomer = { id: 'c1', current_debt: 100 }

    vi.spyOn(ReceiptRepository.prototype, 'getById').mockResolvedValue(mockReceipt as any)
    vi.spyOn(CustomerRepository.prototype, 'getById').mockResolvedValue(mockCustomer as any)
    vi.spyOn(PaymentRepository.prototype, 'create').mockResolvedValue({ id: 'p1' } as any)
    vi.spyOn(ReceiptRepository.prototype, 'update').mockResolvedValue({} as any)
    vi.spyOn(CustomerRepository.prototype, 'update').mockResolvedValue({} as any)
    vi.spyOn(AuditService.prototype, 'log').mockResolvedValue()

    await service.processPayment({
      receiptId: 'r1',
      customerId: 'c1',
      cashClosureId: 'cl1',
      amount: 100,
      paymentMethod: 'cash',
      receivedAmount: 100,
      changeAmount: 0
    })

    expect(ReceiptRepository.prototype.update).toHaveBeenCalledWith('r1', {
      paid_amount: 100,
      status: 'paid'
    })
    expect(CustomerRepository.prototype.update).toHaveBeenCalledWith('c1', {
      current_debt: 0
    })
  })

  it('debería mantener el recibo como PENDIENTE si el pago es parcial', async () => {
    const mockReceipt = { id: 'r1', total_amount: 100, paid_amount: 0 }
    const mockCustomer = { id: 'c1', current_debt: 100 }

    vi.spyOn(ReceiptRepository.prototype, 'getById').mockResolvedValue(mockReceipt as any)
    vi.spyOn(CustomerRepository.prototype, 'getById').mockResolvedValue(mockCustomer as any)
    vi.spyOn(PaymentRepository.prototype, 'create').mockResolvedValue({ id: 'p1' } as any)
    vi.spyOn(ReceiptRepository.prototype, 'update').mockResolvedValue({} as any)
    vi.spyOn(CustomerRepository.prototype, 'update').mockResolvedValue({} as any)
    vi.spyOn(AuditService.prototype, 'log').mockResolvedValue()

    await service.processPayment({
      receiptId: 'r1',
      customerId: 'c1',
      cashClosureId: 'cl1',
      amount: 40,
      paymentMethod: 'cash',
      receivedAmount: 50,
      changeAmount: 10
    })

    expect(ReceiptRepository.prototype.update).toHaveBeenCalledWith('r1', {
      paid_amount: 40,
      status: 'pending'
    })
    expect(CustomerRepository.prototype.update).toHaveBeenCalledWith('c1', {
      current_debt: 60
    })
  })
})

import { describe, it, expect, vi, beforeEach } from 'vitest'
import { PeriodService } from '@/services/period-service'
