import { Calendar, Lock, Unlock, PlayCircle } from 'lucide-react'
import { closePeriodAction } from './actions'
import { formatDate } from '@/lib/utils'

export function PeriodsList({ initialPeriods }: { initialPeriods: any[] }) {
  const [periods, setPeriods] = useState(initialPeriods)
  const [loading, setLoading] = useState<string | null>(null)
  const [error, setError] = useState<string | null>(null)

  const handleClosePeriod = async (id: string) => {
    // if (!confirm('¿Estás seguro de cerrar este periodo? Se generarán los recibos para todos los clientes y no se podrán editar más lecturas.')) {
    //   return
    // }

    setError(null)
    setLoading(id)
    try {
      const result = await closePeriodAction(id) as any
      const generated = result?.receiptsGenerated ?? 0
      setPeriods(prev =>
        prev.map(p => p.id === id ? { ...p, is_closed: true, closed_at: new Date().toISOString() } : p)
      )
      alert(`Periodo cerrado exitosamente. Se generaron ${generated} recibos.`)
    } catch {
      setError('Error al cerrar el periodo.')
    } finally {
      setLoading(null)
    }
  }

  return (
    <div className="rounded-md border bg-card">
      {error && (
        <div className="bg-destructive/10 text-destructive text-sm p-3 rounded-t-lg border-b">
          {error}
        </div>
      )}
      <Table>
        <TableHeader>
          <TableRow>
            <TableHead>Periodo</TableHead>
            <TableHead>Inicio</TableHead>
            <TableHead>Fin</TableHead>
            <TableHead>Estado</TableHead>
            <TableHead className="text-right">Acciones</TableHead>
          </TableRow>
        </TableHeader>
        <TableBody>
          {periods.length === 0 ? (
            <TableRow>
              <TableCell colSpan={5} className="h-24 text-center">
                No hay periodos registrados.
              </TableCell>
            </TableRow>
          ) : (
            periods.map((period) => (
              <TableRow key={period.id}>
                <TableCell className="font-bold flex items-center gap-2">
                  <Calendar className="h-4 w-4 text-muted-foreground" />
                  {period.name}
                </TableCell>
                <TableCell>{formatDate(period.start_date)}</TableCell>
                <TableCell>{formatDate(period.end_date)}</TableCell>
                <TableCell>
                  <Badge variant={period.is_closed ? 'secondary' : 'default'} className="gap-1">
                    {period.is_closed ? (
                      <><Lock className="h-3 w-3" /> Cerrado</>
                    ) : (
                      <><Unlock className="h-3 w-3" /> Abierto</>
                    )}
                  </Badge>
                </TableCell>
                <TableCell className="text-right">
                  {!period.is_closed && (
                    <Button 
                      size="sm" 
                      variant="outline" 
                      className="gap-2 border-primary text-primary hover:bg-primary/5"
                      onClick={() => handleClosePeriod(period.id)}
                      disabled={loading === period.id}
                    >
                      <PlayCircle className="h-4 w-4" />
                      {loading === period.id ? 'Procesando...' : 'Cerrar y Generar Recibos'}
                    </Button>
                  )}
                  {period.is_closed && (
                    <span className="text-xs text-muted-foreground italic">
                      Cerrado el {formatDate(period.closed_at)}
                    </span>
                  )}
                </TableCell>
              </TableRow>
            ))
          )}
        </TableBody>
      </Table>
    </div>
  )
}

'use client'

import { useState } from 'react'
import { Button } from '@/components/ui/button'
import { Download, Printer, XCircle } from 'lucide-react'
import { pdfService } from '@/services/pdf-service'
import { cancelReceiptAction } from '../actions'
import { useRouter } from 'next/navigation'

export function ReceiptDetailActions({ receipt }: { receipt: any }) {
  const router = useRouter()
  const [cancelError, setCancelError] = useState<string | null>(null)

  const handleDownload = () => {
    pdfService.generateReceiptPdf(receipt)
  }

  const handleCancel = async () => {
    if (!confirm('¿Estás seguro de anular este recibo? Esta acción es irreversible.')) {
      return
    }

    setCancelError(null)
    try {
      await cancelReceiptAction(receipt.id, 'Anulación administrativa')
      router.refresh()
    } catch {
      setCancelError('Error al anular el recibo')
    }
  }

  return (
    <div className="space-y-2">
      {cancelError && (
        <div className="bg-destructive/10 text-destructive text-sm p-3 rounded-lg">
          {cancelError}
        </div>
      )}
      <div className="flex gap-2">
      <Button variant="outline" className="gap-2" onClick={() => window.print()}>
        <Printer className="h-4 w-4" /> Imprimir
      </Button>
      <Button variant="outline" className="gap-2" onClick={handleDownload}>
        <Download className="h-4 w-4" /> Descargar PDF
      </Button>
      {receipt.status !== 'cancelled' && (
        <Button variant="destructive" className="gap-2" onClick={handleCancel}>
          <XCircle className="h-4 w-4" /> Anular Recibo
        </Button>
      )}
      </div>
    </div>
  )
}

