export class StorageService {
  private supabase: SupabaseClient<Database>
  private bucketName = 'reading-photos'

  constructor(supabaseClient?: SupabaseClient<Database>) {
    this.supabase = supabaseClient ?? createClient()
  }

  /**
   * Sube una foto de lectura a Supabase Storage
   * @param base64Image - Imagen en formato base64
   * @param fileName - Nombre del archivo (opcional, se genera uno si no se proporciona)
   * @returns URL pública de la imagen subida
   */
  async uploadReadingPhoto(base64Image: string, fileName?: string): Promise<string> {
    try {
      // Generar nombre único si no se proporciona
      const finalFileName = fileName || `reading_${Date.now()}_${Math.random().toString(36).substring(7)}.jpg`

      // Convertir base64 a blob
      const base64Data = base64Image.replace(/^data:image\/\w+;base64,/, '')
      const byteCharacters = atob(base64Data)
      const byteNumbers = new Array(byteCharacters.length)

      for (let i = 0; i < byteCharacters.length; i++) {
        byteNumbers[i] = byteCharacters.charCodeAt(i)
      }

      const byteArray = new Uint8Array(byteNumbers)
      const blob = new Blob([byteArray], { type: 'image/jpeg' })
      const file = new File([blob], finalFileName, { type: 'image/jpeg' })

      // Subir archivo
      const { data, error } = await this.supabase.storage
        .from(this.bucketName)
        .upload(`public/${finalFileName}`, file, {
          cacheControl: '3600',
          upsert: false
        })

      if (error) {
        throw error
      }

      // Obtener URL pública
      const { data: { publicUrl } } = this.supabase.storage
        .from(this.bucketName)
        .getPublicUrl(`public/${finalFileName}`)

      return publicUrl
    } catch (error) {
      console.error('Error uploading photo:', error)
      throw new Error('Error al subir la foto')
    }
  }

  /**
   * Elimina una foto de lectura
   * @param filePath - Ruta del archivo en el bucket
   */
  async deleteReadingPhoto(filePath: string): Promise<void> {
    try {
      const { error } = await this.supabase.storage
        .from(this.bucketName)
        .remove([filePath])

      if (error) {
        throw error
      }
    } catch (error) {
      console.error('Error deleting photo:', error)
      throw new Error('Error al eliminar la foto')
    }
  }

  /**
   * Obtiene la URL de una foto
   * @param fileName - Nombre del archivo
   * @returns URL pública
   */
  getPhotoUrl(fileName: string): string {
    const { data: { publicUrl } } = this.supabase.storage
      .from(this.bucketName)
      .getPublicUrl(`public/${fileName}`)

    return publicUrl
  }
}

export const storageService = new StorageService()

export function getStorageService(supabaseClient: SupabaseClient<Database>) {
  return new StorageService(supabaseClient)
}

import { serve } from "https://deno.land/std@0.168.0/http/server.ts"
import { createClient } from "https://esm.sh/@supabase/supabase-js@2.105.1"

const corsHeaders = {
  'Access-Control-Allow-Origin': '*',
  'Access-Control-Allow-Headers': 'authorization, x-client-info, apikey, content-type',
}

serve(async (req) => {
  if (req.method === 'OPTIONS') {
    return new Response('ok', { headers: corsHeaders })
  }

  try {
    const supabaseClient = createClient(
      Deno.env.get('SUPABASE_URL') ?? '',
      Deno.env.get('SUPABASE_SERVICE_ROLE_KEY') ?? ''
    )

    const { period_id } = await req.json()

    if (!period_id) throw new Error('period_id is required')

    // 1. Obtener periodo y configuración municipal
    const { data: period } = await supabaseClient
      .from('billing_periods')
      .select('*')
      .eq('id', period_id)
      .single()

    // 2. Obtener clientes activos con sus lecturas del periodo
    const { data: customers } = await supabaseClient
      .from('customers')
      .select(`
        *,
        tariffs (*, tariff_tiers (*)),
        readings (*)
      `)
      .eq('is_active', true)

    const results = []

    // 3. Generar recibo para cada cliente
    for (const customer of customers) {
      const reading = customer.readings?.find((r: any) => r.billing_period_id === period_id)

      // Si no hay lectura, se puede estimar o dejar en 0 consumo
      const consumption = reading ? reading.consumption : 0

      // Lógica de cálculo (simplificada para el ejemplo)
      // En producción llamaría a la función SQL calculate_energy_amount o replicaría aquí
      const energy_amount = 0 // TODO: Implementar cálculo exacto

      const receipt = {
        receipt_number: Date.now(), // TODO: Secuencial real
        customer_id: customer.id,
        reading_id: reading?.id || null,
        billing_period_id: period_id,
        previous_reading: reading?.previous_reading || 0,
        current_reading: reading?.current_reading || 0,
        consumption_kwh: consumption,
        energy_amount,
        fixed_charges: 9.20, // Suma de fijos del seed
        subtotal: energy_amount + 9.20,
        previous_debt: customer.current_debt,
        total_amount: energy_amount + 9.20 + customer.current_debt,
        due_date: new Date(new Date(period.end_date).getTime() + 20 * 24 * 60 * 60 * 1000).toISOString(),
        period_start: period.start_date,
        period_end: period.end_date,
        status: 'pending'
      }

      const { data: newReceipt } = await supabaseClient
        .from('receipts')
        .insert(receipt)
        .select()
        .single()

      results.push(newReceipt)
    }

    return new Response(
      JSON.stringify({ message: `Se generaron ${results.length} recibos.`, count: results.length }),
      { headers: { ...corsHeaders, 'Content-Type': 'application/json' }, status: 200 }
    )

  } catch (error: any) {
    return new Response(
      JSON.stringify({ error: error.message }),
      { headers: { ...corsHeaders, 'Content-Type': 'application/json' }, status: 400 }
    )
  }
})
